const body = $node['Webhook In'].json.body || $node['Webhook In'].json || {};

const input = {
  title: String(body.title || ''),
  source: String(body.source || ''),
  url: String(body.url || ''),
  content: String(body.content || body.text || ''),
  prompt: String(body.prompt || '请将输入内容清洗并改写为一篇自然、连贯、可读的中文文章。避免营销口吻，不添加无依据信息。'),
  audience: String(body.audience || '普通读者'),
  tone: String(body.tone || '专业、简洁、自然'),
  model: String(body.model || 'gpt-4.1-mini')
};

if (!input.content) {
  throw new Error('content 不能为空');
}

return [{ json: input }];

const raw = $node['OpenAI Clean Writer'].json.choices?.[0]?.message?.content || '{}';
let article;
try {
  article = JSON.parse(raw);
} catch {
  article = {
    title_cn: $node['Normalize Input'].json.title || '未命名文章',
    summary_cn: '',
    article_cn: String(raw || ''),
    keywords: [],
    quality_check: {
      facts_only_from_input: false,
      removed_noise: false,
      language: 'zh-CN'
    }
  };
}

return [{
  json: {
    ok: true,
    input_meta: {
      source: $node['Normalize Input'].json.source,
      url: $node['Normalize Input'].json.url,
      model: $node['Normalize Input'].json.model
    },
    article
  }
}];
